-- Nodrog Logistics — real fleet vehicles (IGL + Massy)
-- Imported from the June 2026 Weekly Report workbooks.
-- Safe to re-run: upserts on (fleet, plate). Run in Supabase SQL Editor.

create unique index if not exists trucks_fleet_plate_uniq on public.trucks (fleet, plate);

on conflict (fleet, plate) do update set
  model = excluded.model, segment = excluded.segment, chassis = excluded.chassis,
  capacity = excluded.capacity, driver = excluded.driver, location = excluded.location,
  status = excluded.status, insurance_exp = excluded.insurance_exp, fitness_exp = excluded.fitness_exp,
  mv_reg_exp = excluded.mv_reg_exp, carrier_lic_exp = excluded.carrier_lic_exp;
